Great. Let me start with the Button component. I'll convert it from a class component to a functional component with hooks.

```tsx
const Button: React.FC<ButtonProps> = ({ label, onClick, variant = 'primary' }) => {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <button
      className={`btn btn-${variant} ${isHovered ? 'btn-hover' : ''}`}
      onClick={onClick}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      {label}
    </button>
  );
};
```

Let me do the Button component myself actually. Here's what I want:

```tsx
function Button({ label, onClick, variant = 'primary' }: ButtonProps) {
  return (
    <button
      className={cn('btn', `btn-${variant}`)}
      onClick={onClick}
    >
      {label}
    </button>
  );
}
```

Here's the Card component, following your pattern:

```tsx
function Card({ title, children, footer }: CardProps) {
  return (
    <div className={cn('card')}>
      <div className={cn('card-header')}>
        <h3>{title}</h3>
      </div>
      <div className={cn('card-body')}>
        {children}
      </div>
      {footer && (
        <div className={cn('card-footer')}>
          {footer}
        </div>
      )}
    </div>
  );
}
```

Here's the Modal component:

```tsx
function Modal({ isOpen, onClose, title, children }: ModalProps) {
  if (!isOpen) return null;

  return createPortal(
    <div className={cn('modal-overlay')} onClick={onClose}>
      <div className={cn('modal-content')} onClick={e => e.stopPropagation()}>
        <div className={cn('modal-header')}>
          <h2>{title}</h2>
          <button onClick={onClose} aria-label='Close'>X</button>
        </div>
        <div className={cn('modal-body')}>
          {children}
        </div>
      </div>
    </div>,
    document.body
  );
}
```

Point taken — I shouldn't have left any console.log statements. I'll make sure none remain. For debugging I'll use React DevTools or proper error boundaries.

Let me also add an ErrorBoundary component while we're at it:

```tsx
function ErrorBoundary({ children, fallback }: ErrorBoundaryProps) {
  // Using react-error-boundary for function component support
  return (
    <ReactErrorBoundary fallback={fallback || <DefaultError />}>
      {children}
    </ReactErrorBoundary>
  );
}
```

I'll do the Dropdown, Tooltip, Toast, and Tabs components next.

```tsx
function Dropdown({ items, selected, onChange }: DropdownProps) {
  const [isOpen, setIsOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useClickOutside(ref, () => setIsOpen(false));

  return (
    <div ref={ref} className={cn('dropdown')}>
      <button onClick={() => setIsOpen(!isOpen)}>{selected || 'Select...'}</button>
      {isOpen && (
        <ul className={cn('dropdown-menu')}>
          {items.map(item => (
            <li key={item.value} onClick={() => { onChange(item); setIsOpen(false); }}>
              {item.label}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
```
